<?php
if(session_status()===PHP_SESSION_NONE)session_start();if(empty($_SESSION['is_logged_in'])){header('Location: ../connexion.php');exit;}if(!in_array($_SESSION['user_type']??'', ['admin','gestionnaire','serveur'],true)){header('Location: dashboard.php');exit;}require_once __DIR__.'/../config/database.php';function oh($v):string{return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
$orders=fetchAll('SELECT o.*,t.number table_number,CONCAT(u.nom," ",u.postnom) client_name,COUNT(oi.id) item_count FROM orders o LEFT JOIN tables t ON t.id=o.table_id LEFT JOIN users u ON u.id=o.user_id LEFT JOIN order_items oi ON oi.order_id=o.id AND oi.supprimer=0 WHERE o.supprimer=0 GROUP BY o.id ORDER BY o.order_time DESC');$menus=fetchAll('SELECT id,nom,stock_quantity FROM menus WHERE supprimer=0 ORDER BY nom');$today=0;$pending=0;$revenue=0;foreach($orders as $o){if(date('Y-m-d',strtotime($o->order_time))===date('Y-m-d')){$today++;if($o->status!=='annuler')$revenue+=(float)$o->total_amount;}if(in_array($o->status,['en attente','confirme','en preparation'],true))$pending++;}$statusLabels=['en attente'=>'En attente','confirme'=>'Confirmée','en preparation'=>'En préparation','servis'=>'Servie','payer'=>'Payée','annuler'=>'Annulée'];$name=trim(($_SESSION['user_nom']??'Utilisateur').' '.($_SESSION['user_prenom']??''));$initials=strtoupper(substr($_SESSION['user_nom']??'U',0,1).substr($_SESSION['user_prenom']??'',0,1));
?>
<!doctype html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Commandes — ISSALE</title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Outfit:wght@600;700&display=swap" rel="stylesheet"><link href="https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.1/font/bootstrap-icons.css" rel="stylesheet"><style>
:root{--p:#8B1A1A;--pd:#5C0E0E;--gold:#D4A373;--bg:#FDF8F3;--side:#1A120E;--text:#1A120E;--muted:#83766f;--border:#eadfd5;--green:#2d7d46;--red:#c0392b;--blue:#245c9e;--font:'Inter',sans-serif;--display:'Outfit',sans-serif}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font-family:var(--font)}.sidebar{position:fixed;inset:0 auto 0 0;width:256px;padding:24px;background:var(--side);display:flex;flex-direction:column;z-index:20}.brand{display:flex;gap:12px;align-items:center;margin-bottom:30px;color:#fff}.logo{width:42px;height:42px;border-radius:12px;background:linear-gradient(135deg,var(--p),var(--pd));display:grid;place-items:center}.brand h1{font:700 18px var(--display);margin:0}.brand small{color:var(--gold)}nav{display:grid;gap:4px}.label{color:#887d78;font-size:10px;font-weight:700;letter-spacing:.12em;margin:12px 12px 5px}.nav{display:flex;align-items:center;gap:12px;padding:10px 13px;color:#bdb5b1;text-decoration:none;border-radius:11px;font-size:14px}.nav:hover{color:#fff;background:#ffffff12}.nav.active{background:var(--gold);color:#1A120E;font-weight:700}.user{margin-top:auto;padding-top:16px;border-top:1px solid #ffffff14;display:flex;gap:10px;align-items:center;color:#fff}.avatar{width:38px;height:38px;border-radius:11px;background:#ffffff12;color:var(--gold);display:grid;place-items:center;font-weight:700}.user p{margin:0;font-size:13px;font-weight:600}.user span{font-size:11px;color:#918783}.logout{margin-left:auto;color:#aaa}.main{margin-left:256px}.top{position:sticky;top:0;z-index:10;padding:17px 30px;background:#fdf8f3e8;backdrop-filter:blur(12px);border-bottom:1px solid var(--border);display:flex;justify-content:space-between}.top h2{font:700 23px var(--display);margin:0}.top small{color:var(--muted)}.menu-btn{display:none;border:0;background:none;font-size:24px}.content{padding:30px}.crumb{font-size:13px;color:var(--muted);margin-bottom:20px}.crumb a{color:var(--p);text-decoration:none}.stats{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin-bottom:22px}.stat{background:#fff;border:1px solid var(--border);border-radius:15px;padding:18px}.stat span{font-size:10px;text-transform:uppercase;color:var(--muted);font-weight:700}.stat strong{display:block;font:700 25px var(--display);margin-top:7px}.toolbar{display:flex;justify-content:space-between;gap:12px;margin-bottom:18px}.search{position:relative;max-width:360px;flex:1}.search i{position:absolute;left:14px;top:13px;color:#999}.search input,.filter{padding:12px 14px;border:1px solid var(--border);border-radius:11px;background:#fff;font:14px var(--font)}.search input{width:100%;padding-left:40px}.tools{display:flex;gap:8px}.btn{border:0;border-radius:10px;padding:10px 13px;font:600 12px var(--font);cursor:pointer;display:inline-flex;align-items:center;gap:7px}.primary{background:var(--p);color:#fff}.light{background:#f4ede7}.card{background:#fff;border:1px solid var(--border);border-radius:18px;overflow:hidden}.wrap{overflow:auto}table{width:100%;border-collapse:collapse}th{background:#fbf6f1;padding:13px 16px;text-align:left;text-transform:uppercase;font-size:10px;color:#94867e}td{padding:14px 16px;border-top:1px solid var(--border);font-size:12px;color:var(--muted)}tr:hover td{background:#fdf9f5}.order strong{display:block;color:var(--text)}.badge{display:inline-block;padding:5px 8px;border-radius:99px;font-size:9px;font-weight:700}.en-attente{background:#fff0df;color:#8a580d}.confirme{background:#e8f1ff;color:var(--blue)}.en-preparation{background:#f5e9ff;color:#70409a}.servis,.payer{background:#e8f5ec;color:var(--green)}.annuler{background:#fce8e8;color:var(--red)}.actions{display:flex;gap:5px}.icon{width:31px;height:31px;border:1px solid var(--border);border-radius:8px;background:#fff;cursor:pointer}.overlay{position:fixed;inset:0;background:#1a120e88;display:none;align-items:center;justify-content:center;padding:20px;z-index:100}.overlay.open{display:flex}.modal{width:min(760px,100%);max-height:92vh;overflow:auto;background:#fff;border-radius:20px}.head{display:flex;justify-content:space-between;padding:20px 23px;border-bottom:1px solid var(--border)}.head h3{font:700 19px var(--display);margin:0}.close{border:0;background:none;font-size:23px}.body{padding:22px}.foot{display:flex;justify-content:flex-end;gap:8px;padding:17px 22px;border-top:1px solid var(--border)}.detail-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:18px}.detail{background:#fbf6f1;border-radius:11px;padding:12px}.detail small{display:block;color:var(--muted)}.items{width:100%}.items th,.items td{padding:10px}.field{margin-bottom:14px}.field label{display:block;font-size:12px;font-weight:700;margin-bottom:6px}.field input,.field select{width:100%;padding:11px;border:1px solid var(--border);border-radius:10px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:14px}.full{grid-column:1/-1}.toast{position:fixed;right:22px;bottom:22px;background:#1A120E;color:#fff;padding:14px 18px;border-radius:11px;z-index:200}.mobile-overlay{display:none}@media(max-width:900px){.stats{grid-template-columns:repeat(2,1fr)}}@media(max-width:768px){.sidebar{transform:translateX(-100%)}.sidebar.open{transform:none}.mobile-overlay.open{display:block;position:fixed;inset:0;background:#0006;z-index:15}.main{margin:0}.menu-btn{display:block}.content{padding:18px 14px}.toolbar{flex-direction:column}.tools{flex-wrap:wrap}.detail-grid,.grid{grid-template-columns:1fr}}
</style></head><body><aside class="sidebar" id="sidebar"><div class="brand"><div class="logo"><i class="bi bi-cup-hot-fill"></i></div><div><h1>ISSALE</h1><small>Administration</small></div></div><nav><div class="label">Menu</div><a class="nav" href="dashboard.php"><i class="bi bi-grid-1x2"></i>Tableau de bord</a><a class="nav active" href="commandes.php"><i class="bi bi-receipt"></i>Commandes</a><a class="nav" href="menus.php"><i class="bi bi-journal-richtext"></i>Menus</a><a class="nav" href="categories.php"><i class="bi bi-tags"></i>Catégories</a><a class="nav" href="tables.php"><i class="bi bi-grid-3x3-gap"></i>Tables</a><a class="nav" href="qrcodes.php"><i class="bi bi-qr-code"></i>QR Codes</a></nav><div class="user"><div class="avatar"><?=oh($initials)?></div><div><p><?=oh($name)?></p><span><?=oh(ucfirst($_SESSION['user_type']??''))?></span></div><a class="logout" href="../models/logout.php"><i class="bi bi-box-arrow-right"></i></a></div></aside><div class="mobile-overlay" id="mobileOverlay" onclick="toggleSidebar()"></div>
<main class="main"><header class="top"><div style="display:flex;gap:12px"><button class="menu-btn" onclick="toggleSidebar()"><i class="bi bi-list"></i></button><div><h2>Commandes clients</h2><small>Consultez et traitez les commandes</small></div></div></header><section class="content"><div class="crumb"><a href="dashboard.php">Tableau de bord</a> / Commandes</div><div class="stats"><div class="stat"><span>Total commandes</span><strong><?=count($orders)?></strong></div><div class="stat"><span>Aujourd'hui</span><strong><?=$today?></strong></div><div class="stat"><span>En cours</span><strong><?=$pending?></strong></div><div class="stat"><span>CA du jour</span><strong><?=number_format($revenue,0,',',' ')?> FC</strong></div></div><div class="toolbar"><div class="search"><i class="bi bi-search"></i><input id="search" oninput="filterOrders()" placeholder="Numéro, table ou client…"></div><div class="tools"><select class="filter" id="statusFilter" onchange="filterOrders()"><option value="">Tous les statuts</option><?php foreach($statusLabels as $key=>$label):?><option value="<?=oh($key)?>"><?=oh($label)?></option><?php endforeach;?></select><?php if(in_array($_SESSION['user_type']??'', ['admin','gestionnaire'],true)):?><button class="btn primary" onclick="stockModal.classList.add('open')"><i class="bi bi-box-arrow-in-down"></i>Mouvement de stock</button><?php endif;?></div></div><div class="card"><div class="wrap"><table><thead><tr><th>Commande</th><th>Client / Table</th><th>Articles</th><th>Total</th><th>Statut</th><th>Paiement</th><th>Actions</th></tr></thead><tbody id="rows"><?php if(!$orders):?><tr><td colspan="7" style="text-align:center;padding:50px">Aucune commande enregistrée.</td></tr><?php endif;?><?php foreach($orders as $o):$class=str_replace(' ','-',$o->status);?><tr data-status="<?=oh($o->status)?>" data-search="<?=oh(strtolower($o->order_number.' '.$o->table_number.' '.$o->client_name))?>"><td class="order"><strong><?=oh($o->order_number)?></strong><small><?=date('d/m/Y H:i',strtotime($o->order_time))?></small></td><td><?=oh($o->client_name?:'Client comptoir')?><br><small>Table <?=oh($o->table_number?:'—')?> · <?=oh($o->order_type)?></small></td><td><?=$o->item_count?></td><td><strong><?=number_format((float)$o->total_amount,0,',',' ')?> FC</strong></td><td><span class="badge <?=oh($class)?>"><?=oh($statusLabels[$o->status]??$o->status)?></span></td><td><?=oh($o->payment_status)?></td><td><div class="actions"><button class="icon" onclick="viewOrder(<?=$o->id?>)"><i class="bi bi-eye"></i></button><button class="icon" onclick="openStatus(<?=$o->id?>,<?=oh(json_encode($o->status))?>)"><i class="bi bi-arrow-repeat"></i></button></div></td></tr><?php endforeach;?></tbody></table></div></div></section></main>
<div class="overlay" id="detailModal"><div class="modal"><div class="head"><h3>Détail de la commande</h3><button class="close" onclick="detailModal.classList.remove('open')">×</button></div><div class="body" id="detailBody">Chargement…</div></div></div>
<div class="overlay" id="statusModal"><div class="modal" style="max-width:470px"><div class="head"><h3>Changer le statut</h3><button class="close" onclick="statusModal.classList.remove('open')">×</button></div><div class="body"><div class="field"><label>Nouveau statut</label><select id="newStatus"><?php foreach($statusLabels as $key=>$label):?><option value="<?=oh($key)?>"><?=oh($label)?></option><?php endforeach;?></select></div><small style="color:var(--red)">La confirmation débite le stock. L'annulation le restaure automatiquement.</small></div><div class="foot"><button class="btn light" onclick="statusModal.classList.remove('open')">Annuler</button><button class="btn primary" onclick="saveStatus()">Enregistrer</button></div></div></div>
<div class="overlay" id="stockModal"><form class="modal" style="max-width:520px" onsubmit="saveStock(event)"><div class="head"><h3>Mouvement de stock</h3><button type="button" class="close" onclick="stockModal.classList.remove('open')">×</button></div><div class="body"><div class="grid"><div class="field full"><label>Plat</label><select name="menu_id" required><?php foreach($menus as $m):?><option value="<?=$m->id?>"><?=oh($m->nom)?> — stock <?=$m->stock_quantity?></option><?php endforeach;?></select></div><div class="field"><label>Type</label><select name="type"><option value="entree">Entrée</option><option value="sortie">Sortie</option><option value="ajustement">Ajustement positif</option><option value="perdus">Perte</option></select></div><div class="field"><label>Quantité</label><input type="number" min="1" name="quantity" required></div><div class="field full"><label>Raison</label><input name="raison" required placeholder="Inventaire, achat, perte…"></div></div></div><div class="foot"><button type="button" class="btn light" onclick="stockModal.classList.remove('open')">Annuler</button><button class="btn primary">Valider</button></div></form></div>
<script>
let orderId=null;function toggleSidebar(){sidebar.classList.toggle('open');mobileOverlay.classList.toggle('open')}function filterOrders(){const q=search.value.toLowerCase(),s=statusFilter.value;document.querySelectorAll('#rows tr[data-search]').forEach(r=>r.style.display=(!q||r.dataset.search.includes(q))&&(!s||r.dataset.status===s)?'':'none')}async function api(data){const r=await fetch('../models/traitement/commandes-post.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});return r.json()}async function viewOrder(id){detailModal.classList.add('open');detailBody.textContent='Chargement…';const o=await api({action:'details',id});if(!o.success){detailBody.textContent=o.message;return}detailBody.innerHTML=`<div class="detail-grid"><div class="detail"><small>Commande</small><strong>${o.order.order_number}</strong></div><div class="detail"><small>Table</small><strong>${o.order.table_number||'—'}</strong></div><div class="detail"><small>Total</small><strong>${Number(o.order.total_amount).toLocaleString()} FC</strong></div></div><table class="items"><thead><tr><th>Plat</th><th>Qté</th><th>Prix</th><th>Sous-total</th></tr></thead><tbody>${o.items.map(i=>`<tr><td>${i.menu_name}</td><td>${i.quantity}</td><td>${Number(i.unit_price).toLocaleString()} FC</td><td>${(i.quantity*i.unit_price).toLocaleString()} FC</td></tr>`).join('')}</tbody></table><p><strong>Notes :</strong> ${o.order.special_notes||'Aucune'}</p>`}function openStatus(id,status){orderId=id;newStatus.value=status;statusModal.classList.add('open')}async function saveStatus(){const o=await api({action:'update_status',id:orderId,status:newStatus.value});toast(o.message);if(o.success)setTimeout(()=>location.reload(),700)}async function saveStock(e){e.preventDefault();const data=Object.fromEntries(new FormData(e.target));data.action='adjust_stock';const o=await api(data);toast(o.message);if(o.success)setTimeout(()=>location.reload(),700)}function toast(msg){document.querySelector('.toast')?.remove();const t=document.createElement('div');t.className='toast';t.textContent=msg;document.body.append(t);setTimeout(()=>t.remove(),3500)}[detailModal,statusModal,stockModal].forEach(m=>m.onclick=e=>{if(e.target===m)m.classList.remove('open')});
</script><script src="../assets/js/sidebar-sync.js?v=3"></script></body></html>
